import json
import os
import hashlib
import tempfile
import base64

class Substrato770600CellChladniSweep:
    def __init__(self):
        self.md_b64 = ""
        self.vis_b64 = ""

    def generate_json(self):
        # Decode contents
        md_content = base64.b64decode(self.md_b64).decode("utf-8")
        vis_content = base64.b64decode(self.vis_b64).decode("utf-8")

        # Determine payload to seal
        payload = md_content + vis_content
        sha3 = hashlib.sha256((self.md_b64 + self.vis_b64).encode("utf-8")).hexdigest()

        data = {
            "id": "770-600-CELL-CHLADNI-SWEEP",
            "canonical_seal": sha3,
            "gauss_bonnet_md_b64": self.md_b64,
            "visualizer_py_b64": self.vis_b64
        }

        fd, path = tempfile.mkstemp(suffix=".json", text=True)
        with os.fdopen(fd, "w", encoding="utf-8") as f:
            json.dump(data, f, indent=4)

        return path

if __name__ == "__main__":
    canonizer = Substrato770600CellChladniSweep()
    path = canonizer.generate_json()
    print("Generated canonical JSON report at: " + path)
